import time, uuid, json, functools

def trace_llm(fn):
    @functools.wraps(fn)
    def wrap(*args, **kwargs):
        tid, t0 = str(uuid.uuid4()), time.time()
        resp = fn(*args, **kwargs)
        log = {
            "trace_id": tid,
            "latency_ms": int((time.time() - t0) * 1000),
            "prompt_tokens": resp.usage.prompt_tokens,
            "output_tokens": resp.usage.completion_tokens,
            "output": resp.choices[0].message.content,
        }
        emit(log)  # async ship to your sink
        return resp
    return wrap

PRICING = {  # USD per 1K tokens
    "gpt-4o-mini": {"in": 0.00015, "out": 0.0006},
    "gpt-4o":      {"in": 0.0025,  "out": 0.01},
}

def cost(model, usage):
    p = PRICING[model]
    return round(usage.prompt_tokens / 1000 * p["in"]
               + usage.completion_tokens / 1000 * p["out"], 6)

def emit(log, model="gpt-4o-mini", usage=None):
    if usage:
        log["cost_usd"] = cost(model, usage)
    print(json.dumps(log))  # -> Kafka / DB / OTel

import re

PATTERNS = {
    "email": r"[\w.+-]+@[\w-]+\.[\w.-]+",
    "phone": r"\b\d{3}[-.]?\d{3}[-.]?\d{4}\b",
    "ssn":   r"\b\d{3}-\d{2}-\d{4}\b",
}

def redact(text):
    for tag, pat in PATTERNS.items():
        text = re.sub(pat, f"[{tag}]", text)
    return text

log["prompt"] = redact(raw_prompt)  # never log raw PII
